={
  "from": "{{ $env.CLINIC_FROM_EMAIL }}",
  "to": ["{{ $json.doctor_email }}"],
  "subject": "🚨 URGENT — High Risk Intake: {{ $json.patient_name }} at {{ $json.scheduled_time }}",
  "html": "<div style='font-family: Arial, sans-serif; max-width: 600px; margin: auto; padding: 30px;'><div style='background: #dc2626; color: white; padding: 20px; border-radius: 8px 8px 0 0;'><h2 style='margin:0'>🚨 High Risk Patient — Immediate Attention</h2></div><div style='border: 2px solid #dc2626; border-top: none; padding: 25px; border-radius: 0 0 8px 8px;'><p>Dear {{ $json.doctor_name }},</p><p><strong>{{ $json.patient_name }}</strong> has completed their pre-visit intake and has been flagged as HIGH RISK.</p><div style='background: #fef2f2; border: 1px solid #fca5a5; padding: 15px; border-radius: 6px; margin: 20px 0;'><p style='margin:0; color: #991b1b; font-weight: bold;'>Risk Level: HIGH ⚠️</p><p style='margin: 10px 0 0 0; color: #374151;'>{{ $json.ai_summary }}</p></div><p>Appointment time: <strong>{{ $json.scheduled_time }}</strong></p><p>Please review the full intake in your dashboard before the appointment.</p></div></div>"
}

={
  "from": "{{ $env.CLINIC_FROM_EMAIL }}",
  "to": ["{{ $json.doctor_email }}"],
  "subject": "Intake Ready: {{ $json.patient_name }} — {{ $json.scheduled_time }}",
  "html": "<div style='font-family: Arial, sans-serif; max-width: 600px; margin: auto; padding: 30px;'><div style='background: #059669; color: white; padding: 20px; border-radius: 8px 8px 0 0;'><h2 style='margin:0'>✅ Pre-Visit Intake Complete</h2></div><div style='border: 1px solid #e2e8f0; border-top: none; padding: 25px; border-radius: 0 0 8px 8px;'><p>Dear {{ $json.doctor_name }},</p><p><strong>{{ $json.patient_name }}</strong> has completed their pre-visit check-in.</p><div style='background: #f0fdf4; border: 1px solid #86efac; padding: 15px; border-radius: 6px; margin: 20px 0;'><p style='margin:0; color: #166534; font-weight: bold;'>Risk Level: {{ $json.risk_level | upper }}</p><p style='margin: 10px 0 0 0; color: #374151;'>{{ $json.ai_summary }}</p></div><p>Appointment time: <strong>{{ $json.scheduled_time }}</strong></p><p style='color: #6b7280; font-size: 13px;'>Review the full summary in your dashboard.</p></div></div>"
}
